import{_ as o,o as e,c as r,a2 as a}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"HotSpotOS","description":"Notes on HotSpotOS.","frontmatter":{"title":"HotSpotOS","description":"Notes on HotSpotOS."},"headers":[],"relativePath":"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/hotspotos.md","filePath":"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/hotspotos.md"}'),i={name:"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/hotspotos.md"};function s(l,t,n,p,h,c){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="hotspotos" tabindex="-1">HotSpotOS <a class="header-anchor" href="#hotspotos" aria-label="Permalink to &quot;HotSpotOS&quot;">​</a></h1><p>A Raspberry Pi distribution that starts a WiFi hotspot when it cannot join an existing network, and bridges Ethernet to WiFi clients when wired internet is available.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://github.com/guysoft/HotSpotOS" target="_blank" rel="noreferrer">guysoft/HotSpotOS</a></li><li><a href="http://unofficialpi.org/Distros/HotSpotOS" target="_blank" rel="noreferrer">Download image</a></li><li><a href="https://github.com/guysoft/pi-imager/releases" target="_blank" rel="noreferrer">pi-imager community builds</a></li></ul><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>Based on <a href="https://github.com/guysoft/CustomPiOS" target="_blank" rel="noreferrer">CustomPiOS</a> and auto-hotspot scripts (derived from <a href="http://www.raspberryconnect.com/network/item/330-raspberry-pi-auto-wifi-hotspot-switch-internet" target="_blank" rel="noreferrer">roboberry’s approach</a>).</p><ol><li>Flash the image like any Raspberry Pi OS image</li><li>Optionally set WiFi in <code>hotspotos-wpa-supplicant.txt</code> on the boot partition</li><li>Boot — if WiFi joins, behaves like normal Pi OS; otherwise AP <strong><code>hotspot</code></strong> / password <strong><code>raspberry</code></strong></li><li>Ethernet connected → bridges WAN to the hotspot</li><li>SSH: <code>hotspot.lan</code> (Bonjour) or router-assigned IP; user <code>pi</code> / password <code>raspberry</code> (change with <code>passwd</code>)</li></ol><p>Default hotspot IP: <strong>192.168.50.1</strong>. Hostnames use <code>.lan</code>.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li>Headless WiFi config via <code>hotspotos-wpa-supplicant.txt</code></li><li>IPv6 with prefix delegation</li><li>Pi 3 / 3B+ / Zero W supported (see repo for current hardware notes)</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./README.html">Raspberry Pi Hotspot</a></li><li><a href="./kupiki-hotspot-script.html">Kupiki Hotspot Script</a></li></ul>',12)])])}const b=o(i,[["render",s]]);export{u as __pageData,b as default};
